import java.util.*;
import java.util.stream.*;

public class DockerfileAnalyzer {

    public record Instruction(String command, String args) {}

    private final List<Instruction> instructions;

    public DockerfileAnalyzer(List<String> lines) {
        this.instructions = lines.stream()
            .filter(l -> !l.isBlank() && !l.startsWith("#"))
            .map(l -> {
                int space = l.indexOf(' ');
                if (space < 0) return new Instruction(l.toUpperCase(), "");
                return new Instruction(l.substring(0, space).toUpperCase(),
                                       l.substring(space + 1).trim());
            })
            .collect(Collectors.toList());
    }

