        // TODO
        return warnings;
    }

    public boolean hasOptimalCopyOrder() {
        // Returns true if COPY instructions for source code come AFTER RUN for dependencies
        // (i.e., at least one RUN instruction appears before the last COPY)
        return false; // TODO
    }

    public static void main(String[] args) {
        List<String> dockerfile = List.of(
            "FROM openjdk:17",
            "WORKDIR /app",
            "COPY pom.xml .",
            "RUN mvn dependency:go-offline",
